func (q *Queries) UpdateTransactionFields(ctx context.Context, arg UpdateTransactionFieldsParams) (Transaction, error) {
	row := q.db.QueryRow(ctx, updateTransactionFields,
		arg.SetAmount,
		arg.NewAmount,
		arg.SetDescription,
		arg.NewDescription,
		arg.SetDate,
		arg.NewDate,
		arg.SetCategory,
		arg.NewCategory,
		arg.SetVatAmount,
		arg.NewVatAmount,
		arg.ID,
		arg.CompanyID,
	)
	var i Transaction
	err := row.Scan(
		&i.ID,
		&i.CompanyID,
		&i.SessionID,
		&i.SourceType,
		&i.SourceFileID,
		&i.RowIndex,
		&i.Date,
		&i.Description,
		&i.Amount,
		&i.VatAmount,
		&i.VatType,
		&i.Category,
		&i.Tin,
		&i.Confidence,
		&i.ClassificationSource,
		&i.RawData,
		&i.MatchGroupID,
		&i.MatchStatus,
		&i.EwtRate,
		&i.EwtAmount,
		&i.AtcCode,
		&i.SupplierID,
		&i.CreatedAt,
		&i.UpdatedAt,
		&i.JournalEntryID,
		&i.ProjectTag,
		&i.FromCurrency,
		&i.ToCurrency,
		&i.ExchangeRate,
		&i.FromAmount,
		&i.SubmittedBy,
	)
	return i, err
}

